import threading
from typing import Dict, List
from dataclasses import dataclass
from decimal import Decimal

@dataclass
class Transaction:
    transaction_id: str
    account_id: str
    amount: Decimal
    transaction_type: str  # 'debit' or 'credit'
    timestamp: float

class Account:
    def __init__(self, account_id: str, balance: Decimal = Decimal('0.00')):
        self.account_id = account_id
        self.balance = balance
        self.lock = threading.RLock()

class FinancialProcessor:
    def __init__(self):
        self.accounts: Dict[str, Account] = {}
        self.transactions: List[Transaction] = []
        self.lock = threading.RLock()
    
    def add_account(self, account_id: str, initial_balance: Decimal = Decimal('0.00')):
        with self.lock:
            if account_id not in self.accounts:
                self.accounts[account_id] = Account(account_id, initial_balance)
    
    def process_transaction(self, transaction: Transaction) -> bool:
        with self.lock:
            if transaction.account_id not in self.accounts:
                return False
            
            account = self.accounts[transaction.account_id]
            
            with account.lock:
                if transaction.transaction_type == 'debit':
                    if account.balance >= transaction.amount:
                        account.balance -= transaction.amount
                    else:
                        return False
                elif transaction.transaction_type == 'credit':
                    account.balance += transaction.amount
                else:
                    return False
                
                self.transactions.append(transaction)
                return True
    
    def get_balance(self, account_id: str) -> Decimal:
        with self.lock:
            if account_id in self.accounts:
                with self.accounts[account_id].lock:
                    return self.accounts[account_id].balance
            return Decimal('0.00')
    
    def batch_process(self, transactions: List[Transaction]) -> bool:
        with self.lock:
            # Validate all transactions first
            valid_transactions = []
            for transaction in transactions:
                if transaction.account_id not in self.accounts:
                    return False
                
                account = self.accounts[transaction.account_id]
                with account.lock:
                    if transaction.transaction_type == 'debit':
                        if account.balance < transaction.amount:
                            return False
                    valid_transactions.append(transaction)
            
            # Execute all transactions
            for transaction in valid_transactions:
                account = self.accounts[transaction.account_id]
                with account.lock:
                    if transaction.transaction_type == 'debit':
                        account.balance -= transaction.amount
                    elif transaction.transaction_type == 'credit':
                        account.balance += transaction.amount
                    
                    self.transactions.append(transaction)
            
            return True